head.b:skin:
:root{--black:#000;--white:#fff;--bg:#fff;--grey:#6b6b6b;--grey-light:#f4f4f4;--gold:#d4af37;--gold-dark:#b8951f;--red:#e63946;--blue:#1a1a2e;--dark:#0a0a0a;--font-body:'Inter',sans-serif;--font-button:'Oswald',sans-serif;--font-heading:'Oswald',sans-serif}
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth;overflow-x:hidden}
body{font-family:var(--font-body);font-size:16px;line-height:1.55;color:var(--black);background:var(--bg);overflow-x:hidden;-webkit-font-smoothing:antialiased}
img{max-width:100%;height:auto;display:block}
a{color:inherit;text-decoration:none;transition:color .25s}
ul,ol{list-style:none}
button,input,textarea{font-family:inherit;border:none;outline:none;background:none}
h1,h2,h3,h4,h5,h6{font-family:var(--font-heading);font-weight:600;line-height:1.1;text-transform:uppercase}
.wrapper{max-width:1440px;margin:0 auto;padding:0 32px}
.wrapper.wider{max-width:1600px}
.full-grid{display:grid;grid-template-columns:repeat(12,1fr);gap:30px}
.col-span-2{grid-column:span 2}.col-span-3{grid-column:span 3}.col-span-4{grid-column:span 4}.col-span-5{grid-column:span 5}.col-span-6{grid-column:span 6}.col-span-7{grid-column:span 7}.col-span-8{grid-column:span 8}.col-span-9{grid-column:span 9}.col-span-12,.col-span-full{grid-column:1/-1}
.text-3xl{font-size:42px}.text-4xl{font-size:56px}.text-2xl{font-size:32px}.text-xl{font-size:22px}.text-lg{font-size:17px;line-height:1.6}.text-base{font-size:15px}.text-sm{font-size:13px}
.text-white{color:var(--white)}.text-gold{color:var(--gold)}.bg-black{background:var(--black)}.bg-grey-light{background:var(--grey-light)}
.mt-4{margin-top:16px}.mt-6{margin-top:24px}.mt-8{margin-top:32px}.mt-10{margin-top:40px}.mt-14{margin-top:56px}.mt-20{margin-top:80px}.mt-28{margin-top:112px}
.mb-3{margin-bottom:12px}.mb-6{margin-bottom:24px}.mb-8{margin-bottom:32px}.mb-10{margin-bottom:40px}.mb-12{margin-bottom:48px}.mb-14{margin-bottom:56px}.mb-28{margin-bottom:112px}
.pt-10{padding-top:40px}.pt-16{padding-top:64px}.pt-20{padding-top:80px}.pb-8{padding-bottom:32px}.pb-16{padding-bottom:64px}.pb-20{padding-bottom:80px}
.text-left{text-align:left}.text-center{text-align:center}.text-right{text-align:right}
.button{display:inline-block;padding:14px 30px;font-family:var(--font-button);font-size:14px;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;cursor:pointer;transition:all .3s ease;border:2px solid transparent}
.button.yellow,.button.gold{background:var(--gold);color:var(--black)}
.button.yellow:hover,.button.gold:hover{background:var(--gold-dark);transform:translateY(-2px)}
.button.red{background:var(--red);color:var(--white)}
.button.red:hover{background:#c82a37;transform:translateY(-2px)}
.button.white-transparent{background:transparent;border:2px solid var(--white);color:var(--white)}
.button.white-transparent:hover{background:var(--white);color:var(--black)}
.tag{display:inline-block;padding:4px 10px;background:var(--gold);color:var(--black);font-size:11px;font-family:var(--font-button);font-weight:600;text-transform:uppercase;letter-spacing:1px;margin-right:6px;margin-bottom:6px}

body.script:
//
function toggleNav(){
  var ov=document.getElementById('overlayNav');
  var tg=document.getElementById('menuToggle');
  ov.classList.toggle('active');
  tg.classList.toggle('active');
  document.body.style.overflow=ov.classList.contains('active')?'hidden':'';
}
window.addEventListener('scroll',function(){
  var h=document.getElementById('bpaHeader');
  if(!h)return;
  if(window.scrollY>50)h.classList.add('scrolled');
  else h.classList.remove('scrolled');
});
var currSlide=0;
var slides=document.querySelectorAll('.hero-slide');
var dots=document.querySelectorAll('.slider-dot');
function goToSlide(n){
  if(!slides.length)return;
  slides[currSlide].classList.remove('active');
  if(dots[currSlide])dots[currSlide].classList.remove('active');
  currSlide=n;
  slides[currSlide].classList.add('active');
  if(dots[currSlide])dots[currSlide].classList.add('active');
}
function nextSlide(){if(slides.length)goToSlide((currSlide+1)%slides.length);}
if(slides.length>1)setInterval(nextSlide,5500);
function subscribe(e){
  e.preventDefault();
  var email=document.getElementById('email').value;
  var resp=document.getElementById('nlResponse');
  if(email){resp.textContent='Thank you for subscribing to BPA newsletter!';document.getElementById('signup_form').reset();}
  return false;
}
//
